{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "description": "Drawing canvas with freehand, shapes, layers, and save/load support",
  "main": "index.ts",
  "modnet": {
    "contentType": "art",
    "structure": "form",
    "mechanics": ["track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "@plaited/template": "latest"
  }
}

export type Tool = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type LayerData = {
  id: string
  name: string
  visible: boolean
  dataUrl: string
}

export type Drawing = {
  id: string
  name: string
  width: number
  height: number
  layers: LayerData[]
  createdAt: string
  updatedAt: string
}

export type SaveRequest = {
  name: string
  dataUrl: string
  layers: LayerData[]
  width: number
  height: number
}

export type IndexEntry = {
  id: string
  name: string
  updatedAt: string
}

import type { Drawing, SaveRequest, IndexEntry } from './types'

const DATA_DIR = './data'

const loadIndex = async (): Promise<IndexEntry[]> => {
  const file = Bun.file(`${DATA_DIR}/index.json`)
  if (!(await file.exists())) return []
  return file.json()
}

const writeIndex = async (index: IndexEntry[]): Promise<void> => {
  await Bun.write(`${DATA_DIR}/index.json`, JSON.stringify(index, null, 2))
}

export const saveDrawing = async (req: SaveRequest): Promise<Drawing> => {
  const id = crypto.randomUUID()
  const now = new Date().toISOString()

  const drawing: Drawing = {
    id,
    name: req.name,
    width: req.width,
    height: req.height,
    layers: req.layers,
    createdAt: now,
    updatedAt: now,
  }

  const base64 = req.dataUrl.replace(/^data:image\/png;base64,/, '')
  const buffer = Buffer.from(base64, 'base64')
  await Bun.write(`${DATA_DIR}/${id}.png`, buffer)

  await Bun.write(`${DATA_DIR}/${id}.json`, JSON.stringify(drawing, null, 2))

  const index = await loadIndex()
  index.push({ id, name: drawing.name, updatedAt: now })
  await writeIndex(index)

  return drawing
}

export const loadDrawing = async (id: string): Promise<Drawing | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.json`)
  if (!(await file.exists())) return null
  return file.json()
}

export const loadDrawingPng = async (id: string): Promise<ArrayBuffer | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.png`)
  if (!(await file.exists())) return null
  return file.arrayBuffer()
}

export const listDrawings = async (): Promise<IndexEntry[]> => {
  return loadIndex()
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const jsonFile = Bun.file(`${DATA_DIR}/${id}.json`)
  if (!(await jsonFile.exists())) return false

  const { unlink } = await import('node:fs/promises')
  await unlink(`${DATA_DIR}/${id}.json`).catch(() => {})
  await unlink(`${DATA_DIR}/${id}.png`).catch(() => {})

  const index = await loadIndex()
  const filtered = index.filter((entry) => entry.id !== id)
  await writeIndex(filtered)

  return true
}

import { startServer } from './server'

const port = parseInt(process.env.PORT || '3000', 10)
const server = startServer(port)
console.log(`Drawing Canvas running at http://localhost:${server.port}`)

import { renderPage } from './render'
import { saveDrawing, loadDrawing, listDrawings, loadDrawingPng, deleteDrawing } from './storage'
import type { SaveRequest } from './types'

export const startServer = (port = 3000) => {
  return Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' && req.method === 'GET') {
        const html = renderPage()
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      if (url.pathname === '/api/drawings' && req.method === 'GET') {
        const drawings = await listDrawings()
        return Response.json(drawings)
      }

      if (url.pathname === '/api/drawings' && req.method === 'POST') {
        const body = (await req.json()) as SaveRequest
        const drawing = await saveDrawing(body)
        return Response.json(drawing)
      }

      const pngMatch = url.pathname.match(/^\/api\/drawings\/([^/]+)\.png$/)
      if (pngMatch && req.method === 'GET') {
        const png = await loadDrawingPng(pngMatch[1])
        if (!png) return new Response('Not found', { status: 404 })
        return new Response(png, {
          headers: { 'Content-Type': 'image/png' },
        })
      }

      const drawingMatch = url.pathname.match(/^\/api\/drawings\/([^/]+)$/)
      if (drawingMatch) {
        const id = drawingMatch[1]
        if (req.method === 'GET') {
          const drawing = await loadDrawing(id)
          if (!drawing) return new Response('Not found', { status: 404 })
          return Response.json(drawing)
        }
        if (req.method === 'DELETE') {
          const ok = await deleteDrawing(id)
          if (!ok) return new Response('Not found', { status: 404 })
          return new Response('Deleted', { status: 200 })
        }
      }

      return new Response('Not found', { status: 404 })
    },
  })
}

import { h, Fragment } from '@plaited/template'
import { createSSR } from '@plaited/template'

const clientScript = (): string => `
(() => {
  const CANVAS_W = 800;
  const CANVAS_H = 600;

  const mainCanvas = document.getElementById('main-canvas');
  const mainCtx = mainCanvas.getContext('2d');

  let layerCounter = 0;
  const state = {
    tool: 'pen',
    color: '#000000',
    brushSize: 3,
    layers: [],
    activeLayerId: null,
    history: [],
    historyIndex: -1,
    isDrawing: false,
    startPoint: null,
    lastPoint: null,
  };

  // --- Layer Management ---
  const createLayer = (name) => {
    const id = 'layer-' + (++layerCounter);
    const canvas = document.createElement('canvas');
    canvas.width = CANVAS_W;
    canvas.height = CANVAS_H;
    const ctx = canvas.getContext('2d');
    const layer = { id, name: name || ('Layer ' + layerCounter), visible: true, canvas, ctx };
    state.layers.push(layer);
    if (!state.activeLayerId) state.activeLayerId = id;
    updateLayersPanel();
    composite();
    return layer;
  };

  const deleteLayer = (id) => {
    if (state.layers.length <= 1) return;
    state.layers = state.layers.filter(l => l.id !== id);
    if (state.activeLayerId === id) {
      state.activeLayerId = state.layers[0] ? state.layers[0].id : null;
    }
    updateLayersPanel();
    composite();
  };

  const toggleVisibility = (id) => {
    const layer = state.layers.find(l => l.id === id);
    if (layer) layer.visible = !layer.visible;
    updateLayersPanel();
    composite();
  };

  const setActiveLayer = (id) => {
    state.activeLayerId = id;
    updateLayersPanel();
  };

  const getActiveLayer = () => state.layers.find(l => l.id === state.activeLayerId);

  const moveLayerUp = (id) => {
    const idx = state.layers.findIndex(l => l.id === id);
    if (idx < state.layers.length - 1) {
      [state.layers[idx], state.layers[idx + 1]] = [state.layers[idx + 1], state.layers[idx]];
      updateLayersPanel();
      composite();
    }
  };

  const moveLayerDown = (id) => {
    const idx = state.layers.findIndex(l => l.id === id);
    if (idx > 0) {
      [state.layers[idx], state.layers[idx - 1]] = [state.layers[idx - 1], state.layers[idx]];
      updateLayersPanel();
      composite();
    }
  };

  // --- Compositing ---
  const composite = () => {
    mainCtx.clearRect(0, 0, CANVAS_W, CANVAS_H);
    mainCtx.fillStyle = '#ffffff';
    mainCtx.fillRect(0, 0, CANVAS_W, CANVAS_H);
    for (const layer of state.layers) {
      if (!layer.visible) continue;
      mainCtx.drawImage(layer.canvas, 0, 0);
    }
  };

  // --- History ---
  const saveToHistory = () => {
    state.history = state.history.slice(0, state.historyIndex + 1);
    const snapshot = state.layers.map(l => ({
      id: l.id,
      imageData: l.ctx.getImageData(0, 0, CANVAS_W, CANVAS_H),
    }));
    state.history.push(snapshot);
    state.historyIndex = state.history.length - 1;
    if (state.history.length > 50) {
      state.history.shift();
      state.historyIndex--;
    }
    updateUndoRedoButtons();
  };

  const undo = () => {
    if (state.historyIndex <= 0) return;
    state.historyIndex--;
    restoreFromHistory();
  };

  const redo = () => {
    if (state.historyIndex >= state.history.length - 1) return;
    state.historyIndex++;
    restoreFromHistory();
  };

  const restoreFromHistory = () => {
    const snapshot = state.history[state.historyIndex];
    for (const entry of snapshot) {
      const layer = state.layers.find(l => l.id === entry.id);
      if (layer) layer.ctx.putImageData(entry.imageData, 0, 0);
    }
    composite();
    updateLayersPanel();
    updateUndoRedoButtons();
  };

  const updateUndoRedoButtons = () => {
    const undoBtn = document.getElementById('undo-btn');
    const redoBtn = document.getElementById('redo-btn');
    if (undoBtn) undoBtn.disabled = state.historyIndex <= 0;
    if (redoBtn) redoBtn.disabled = state.historyIndex >= state.history.length - 1;
  };

  // --- Drawing ---
  const getCanvasPoint = (e) => {
    const rect = mainCanvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left) * (CANVAS_W / rect.width),
      y: (e.clientY - rect.top) * (CANVAS_H / rect.height),
    };
  };

  const startDraw = (e) => {
    e.preventDefault();
    const layer = getActiveLayer();
    if (!layer || !layer.visible) return;
    const point = getCanvasPoint(e);
    state.isDrawing = true;
    state.startPoint = point;
    state.lastPoint = point;
    saveToHistory();

    if (state.tool === 'pen' || state.tool === 'eraser') {
      layer.ctx.beginPath();
      layer.ctx.moveTo(point.x, point.y);
      if (state.tool === 'eraser') {
        layer.ctx.globalCompositeOperation = 'destination-out';
        layer.ctx.strokeStyle = 'rgba(0,0,0,1)';
      } else {
        layer.ctx.globalCompositeOperation = 'source-over';
        layer.ctx.strokeStyle = state.color;
      }
      layer.ctx.lineWidth = state.brushSize;
      layer.ctx.lineCap = 'round';
      layer.ctx.lineJoin = 'round';
    }
  };

  const draw = (e) => {
    if (!state.isDrawing) return;
    e.preventDefault();
    const point = getCanvasPoint(e);
    const layer = getActiveLayer();
    if (!layer) return;

    if (state.tool === 'pen' || state.tool === 'eraser') {
      layer.ctx.lineTo(point.x, point.y);
      layer.ctx.stroke();
      state.lastPoint = point;
      composite();
    } else {
      composite();
      mainCtx.save();
      mainCtx.strokeStyle = state.color;
      mainCtx.lineWidth = state.brushSize;
      mainCtx.lineCap = 'round';
      mainCtx.lineJoin = 'round';

      if (state.tool === 'rectangle') {
        const w = point.x - state.startPoint.x;
        const ht = point.y - state.startPoint.y;
        mainCtx.strokeRect(state.startPoint.x, state.startPoint.y, w, ht);
      } else if (state.tool === 'circle') {
        const dx = point.x - state.startPoint.x;
        const dy = point.y - state.startPoint.y;
        const radius = Math.sqrt(dx * dx + dy * dy);
        mainCtx.beginPath();
        mainCtx.arc(state.startPoint.x, state.startPoint.y, radius, 0, Math.PI * 2);
        mainCtx.stroke();
      } else if (state.tool === 'line') {
        mainCtx.beginPath();
        mainCtx.moveTo(state.startPoint.x, state.startPoint.y);
        mainCtx.lineTo(point.x, point.y);
        mainCtx.stroke();
      }
      mainCtx.restore();
      state.lastPoint = point;
    }
  };

  const endDraw = (e) => {
    if (!state.isDrawing) return;
    e.preventDefault();
    state.isDrawing = false;
    const layer = getActiveLayer();
    if (!layer) return;

    if (state.tool === 'pen' || state.tool === 'eraser') {
      layer.ctx.closePath();
      layer.ctx.globalCompositeOperation = 'source-over';
    } else {
      const point = state.lastPoint;
      layer.ctx.save();
      layer.ctx.strokeStyle = state.color;
      layer.ctx.lineWidth = state.brushSize;
      layer.ctx.lineCap = 'round';
      layer.ctx.lineJoin = 'round';

      if (state.tool === 'rectangle') {
        const w = point.x - state.startPoint.x;
        const ht = point.y - state.startPoint.y;
        layer.ctx.strokeRect(state.startPoint.x, state.startPoint.y, w, ht);
      } else if (state.tool === 'circle') {
        const dx = point.x - state.startPoint.x;
        const dy = point.y - state.startPoint.y;
        const radius = Math.sqrt(dx * dx + dy * dy);
        layer.ctx.beginPath();
        layer.ctx.arc(state.startPoint.x, state.startPoint.y, radius, 0, Math.PI * 2);
        layer.ctx.stroke();
      } else if (state.tool === 'line') {
        layer.ctx.beginPath();
        layer.ctx.moveTo(state.startPoint.x, state.startPoint.y);
        layer.ctx.lineTo(point.x, point.y);
        layer.ctx.stroke();
      }
      layer.ctx.restore();
    }
    composite();
    updateLayersPanel();
  };

  // --- UI Updates ---
  const updateToolbar = () => {
    document.querySelectorAll('[data-tool]').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.tool === state.tool);
    });
  };

  const updateLayersPanel = () => {
    const list = document.getElementById('layers-list');
    if (!list) return;
    list.innerHTML = '';

    for (let i = state.layers.length - 1; i >= 0; i--) {
      const layer = state.layers[i];
      const item = document.createElement('div');
      item.style.cssText = 'display:flex;align-items:center;gap:6px;padding:6px 8px;border-radius:4px;cursor:pointer;'
        + (layer.id === state.activeLayerId ? 'background:#3a3a5c;border:1px solid #6a6aff;' : 'background:#2a2a2a;border:1px solid #444;');
      item.onclick = () => setActiveLayer(layer.id);

      const thumb = document.createElement('canvas');
      thumb.width = 48;
      thumb.height = 36;
      thumb.style.cssText = 'border:1px solid #555;border-radius:2px;background:#fff;flex-shrink:0;';
      const thumbCtx = thumb.getContext('2d');
      thumbCtx.fillStyle = '#fff';
      thumbCtx.fillRect(0, 0, 48, 36);
      thumbCtx.drawImage(layer.canvas, 0, 0, 48, 36);

      const visBtn = document.createElement('button');
      visBtn.style.cssText = 'background:none;border:1px solid #555;color:#ccc;cursor:pointer;padding:2px 6px;border-radius:3px;font-size:11px;';
      visBtn.textContent = layer.visible ? 'V' : 'H';
      visBtn.title = layer.visible ? 'Hide layer' : 'Show layer';
      visBtn.onclick = (ev) => { ev.stopPropagation(); toggleVisibility(layer.id); };

      const nameSpan = document.createElement('span');
      nameSpan.style.cssText = 'flex:1;font-size:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
      nameSpan.textContent = layer.name;

      const controls = document.createElement('span');
      controls.style.cssText = 'display:flex;gap:2px;';

      const upBtn = document.createElement('button');
      upBtn.style.cssText = 'background:none;border:1px solid #555;color:#ccc;cursor:pointer;padding:1px 4px;border-radius:3px;font-size:10px;';
      upBtn.textContent = '^';
      upBtn.title = 'Move up';
      upBtn.onclick = (ev) => { ev.stopPropagation(); moveLayerUp(layer.id); };

      const downBtn = document.createElement('button');
      downBtn.style.cssText = 'background:none;border:1px solid #555;color:#ccc;cursor:pointer;padding:1px 4px;border-radius:3px;font-size:10px;';
      downBtn.textContent = 'v';
      downBtn.title = 'Move down';
      downBtn.onclick = (ev) => { ev.stopPropagation(); moveLayerDown(layer.id); };

      const delBtn = document.createElement('button');
      delBtn.style.cssText = 'background:none;border:1px solid #733;color:#f66;cursor:pointer;padding:1px 6px;border-radius:3px;font-size:12px;';
      delBtn.textContent = 'x';
      delBtn.title = 'Delete layer';
      delBtn.onclick = (ev) => { ev.stopPropagation(); deleteLayer(layer.id); };

      controls.appendChild(upBtn);
      controls.appendChild(downBtn);
      controls.appendChild(delBtn);

      item.appendChild(thumb);
      item.appendChild(visBtn);
      item.appendChild(nameSpan);
      item.appendChild(controls);
      list.appendChild(item);
    }
  };

  // --- Save / Load ---
  const saveDrawing = async () => {
    const name = prompt('Drawing name:', 'Untitled');
    if (!name) return;

    composite();
    const dataUrl = mainCanvas.toDataURL('image/png');
    const layerData = state.layers.map(l => ({
      id: l.id,
      name: l.name,
      visible: l.visible,
      dataUrl: l.canvas.toDataURL('image/png'),
    }));

    const res = await fetch('/api/drawings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, dataUrl, layers: layerData, width: CANVAS_W, height: CANVAS_H }),
    });

    if (res.ok) {
      const drawing = await res.json();
      alert('Saved: ' + drawing.name + ' (' + drawing.id.slice(0, 8) + ')');
    } else {
      alert('Save failed');
    }
  };

  const loadList = async () => {
    const res = await fetch('/api/drawings');
    if (!res.ok) return;
    const drawings = await res.json();
    if (drawings.length === 0) {
      alert('No saved drawings');
      return;
    }
    const lines = drawings.map(d => d.id.slice(0, 8) + ' - ' + d.name);
    const choice = prompt('Enter drawing ID prefix to load:\\n' + lines.join('\\n'));
    if (!choice) return;
    const match = drawings.find(d => d.id.startsWith(choice.trim()));
    if (match) {
      await loadDrawing(match.id);
    } else {
      alert('Drawing not found');
    }
  };

  const loadDrawing = async (id) => {
    const res = await fetch('/api/drawings/' + id);
    if (!res.ok) { alert('Drawing not found'); return; }
    const drawing = await res.json();

    state.layers = [];
    layerCounter = 0;
    state.history = [];
    state.historyIndex = -1;

    let loaded = 0;
    const total = drawing.layers.length;

    for (const ld of drawing.layers) {
      const layer = createLayer(ld.name);
      layer.visible = ld.visible;
      if (ld.dataUrl) {
        const img = new Image();
        img.onload = () => {
          layer.ctx.drawImage(img, 0, 0);
          loaded++;
          if (loaded === total) {
            composite();
            updateLayersPanel();
            saveToHistory();
          }
        };
        img.src = ld.dataUrl;
      } else {
        loaded++;
      }
    }

    if (total === 0) {
      createLayer('Background');
      saveToHistory();
    }
  };

  // --- Clear ---
  const clearCanvas = () => {
    saveToHistory();
    const layer = getActiveLayer();
    if (layer) {
      layer.ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);
    }
    composite();
    updateLayersPanel();
  };

  // --- Init ---
  const init = () => {
    createLayer('Background');
    saveToHistory();

    mainCanvas.addEventListener('mousedown', startDraw);
    mainCanvas.addEventListener('mousemove', draw);
    mainCanvas.addEventListener('mouseup', endDraw);
    mainCanvas.addEventListener('mouseleave', (e) => { if (state.isDrawing) endDraw(e); });

    mainCanvas.addEventListener('touchstart', (e) => {
      const t = e.touches[0];
      startDraw({ clientX: t.clientX, clientY: t.clientY, preventDefault: () => e.preventDefault() });
    });
    mainCanvas.addEventListener('touchmove', (e) => {
      const t = e.touches[0];
      draw({ clientX: t.clientX, clientY: t.clientY, preventDefault: () => e.preventDefault() });
    });
    mainCanvas.addEventListener('touchend', (e) => {
      endDraw({ preventDefault: () => e.preventDefault() });
    });

    document.querySelectorAll('[data-tool]').forEach(btn => {
      btn.addEventListener('click', () => {
        state.tool = btn.dataset.tool;
        updateToolbar();
      });
    });

    document.getElementById('color-picker').addEventListener('input', (e) => {
      state.color = e.target.value;
    });

    document.getElementById('brush-size').addEventListener('input', (e) => {
      state.brushSize = parseInt(e.target.value, 10);
      document.getElementById('brush-size-label').textContent = e.target.value;
    });

    document.getElementById('undo-btn').addEventListener('click', undo);
    document.getElementById('redo-btn').addEventListener('click', redo);
    document.getElementById('clear-btn').addEventListener('click', clearCanvas);
    document.getElementById('save-btn').addEventListener('click', saveDrawing);
    document.getElementById('load-btn').addEventListener('click', loadList);
    document.getElementById('add-layer-btn').addEventListener('click', () => createLayer());

    document.addEventListener('keydown', (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) { e.preventDefault(); undo(); }
      if ((e.ctrlKey || e.metaKey) && e.key === 'z' && e.shiftKey) { e.preventDefault(); redo(); }
      if ((e.ctrlKey || e.metaKey) && e.key === 's') { e.preventDefault(); saveDrawing(); }
    });

    updateToolbar();
    updateUndoRedoButtons();
    composite();
  };

  init();
})();
`

const toolNames: Array<{ id: string; label: string }> = [
  { id: 'pen', label: 'Pen' },
  { id: 'rectangle', label: 'Rect' },
  { id: 'circle', label: 'Circle' },
  { id: 'line', label: 'Line' },
  { id: 'eraser', label: 'Eraser' },
]

const btnBase = {
  background: '#3a3a3a',
  color: '#ddd',
  border: '1px solid #555',
  padding: '6px 12px',
  borderRadius: '4px',
  cursor: 'pointer',
  fontSize: '13px',
  whiteSpace: 'nowrap',
}

const smallBtn = {
  ...btnBase,
  padding: '4px 10px',
  fontSize: '12px',
}

export const renderPage = (): string => {
  const template = h(
    'html',
    { lang: 'en' },
    h(
      'head',
      {},
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }),
      h('title', {}, 'Drawing Canvas'),
      h('style', {}, `
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: system-ui, -apple-system, sans-serif; background: #1a1a1a; color: #eee; height: 100vh; display: flex; flex-direction: column; overflow: hidden; }
        button:hover { filter: brightness(1.2); }
        button.active, [data-tool].active { background: #5555cc !important; border-color: #7777ff !important; color: #fff !important; }
        button:disabled { opacity: 0.4; cursor: default; filter: none; }
        #main-canvas { cursor: crosshair; display: block; max-width: 100%; max-height: 100%; border-radius: 4px; box-shadow: 0 2px 12px rgba(0,0,0,0.5); }
        input[type="color"] { width: 32px; height: 28px; border: 1px solid #555; border-radius: 4px; cursor: pointer; background: none; padding: 0; }
        input[type="range"] { width: 100px; accent-color: #6a6aff; }
      `),
    ),
    h(
      'body',
      {},
      h(
        'div',
        {
          id: 'toolbar',
          style: {
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            padding: '8px 12px',
            background: '#2c2c2c',
            borderBottom: '1px solid #444',
            flexWrap: 'wrap',
          },
        },
        h(
          'div',
