export type ToolKind = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type StrokeSegment = {
  kind: 'freehand'
  points: Point[]
  color: string
  size: number
}

export type RectangleShape = {
  kind: 'rectangle'
  origin: Point
  width: number
  height: number
  color: string
  size: number
}

export type CircleShape = {
  kind: 'circle'
  center: Point
  radius: number
  color: string
  size: number
}

export type LineShape = {
  kind: 'line'
  start: Point
  end: Point
  color: string
  size: number
}

export type EraserSegment = {
  kind: 'eraser'
  points: Point[]
  size: number
}

export type DrawOp = StrokeSegment | RectangleShape | CircleShape | LineShape | EraserSegment

export type Layer = {
  id: string
