import type { HistoryEntry, Layer } from './types'

export type HistoryManager = {
  push: (entry: HistoryEntry) => void
  undo: (layers: Layer[]) => Layer[] | null
  redo: (layers: Layer[]) => Layer[] | null
  clear: () => void
  canUndo: () => boolean
  canRedo: () => boolean
}

export const createHistoryManager = (maxSize = 100): HistoryManager => {
  const undoStack: HistoryEntry[] = []
  const redoStack: HistoryEntry[] = []

  const push = (entry: HistoryEntry): void => {
    undoStack.push(entry)
    if (undoStack.length > maxSize) {
      undoStack.shift()
    }
    redoStack.length = 0
  }

  const undo = (layers: Layer[]): Layer[] | null => {
    const entry = undoStack.pop()
    if (!entry) return null

    const layer = layers[entry.layerIndex]
    if (!layer) return null

    const removed = layer.ops.pop()
    if (!removed) return null

    redoStack.push(entry)
    return layers
  }

  const redo = (layers: Layer[]): Layer[] | null => {
    const entry = redoStack.pop()
    if (!entry) return null

    const layer = layers[entry.layerIndex]
    if (!layer) return null

    layer.ops.push(entry.op)
    undoStack.push(entry)
    return layers
  }

  const clear = (): void => {
    undoStack.length = 0
    redoStack.length = 0
  }

  const canUndo = (): boolean => undoStack.length > 0
  const canRedo = (): boolean => redoStack.length > 0

  return { push, undo, redo, clear, canUndo, canRedo }
}

import type { Layer } from './types'

let nextId = 1

export const createLayer = (name: string): Layer => ({
  id: `layer-${nextId++}`,
  name,
  visible: true,
  ops: [],
})

export const duplicateLayer = (layer: Layer, newName?: string): Layer => ({
  id: `layer-${nextId++}`,
  name: newName ?? `${layer.name} (copy)`,
  visible: layer.visible,
  ops: [...layer.ops],
})

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  if (fromIndex < 0 || fromIndex >= layers.length) return layers
  if (toIndex < 0 || toIndex >= layers.length) return layers

  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

import type { DrawOp, Layer, CanvasState } from './types'

export type RenderContext = {
  canvas: HTMLCanvasElement
  ctx: CanvasRenderingContext2D
}

export const createRenderContext = (width: number, height: number): RenderContext => {
  const canvas = document.createElement('canvas')
  canvas.width = width
  canvas.height = height
  const ctx = canvas.getContext('2d')!
  return { canvas, ctx }
}

const renderOp = (ctx: CanvasRenderingContext2D, op: DrawOp): void => {
  ctx.lineJoin = 'round'
  ctx.lineCap = 'round'

  switch (op.kind) {
    case 'freehand': {
      if (op.points.length < 2) return
      ctx.strokeStyle = op.color
      ctx.lineWidth = op.size
      ctx.globalCompositeOperation = 'source-over'
      ctx.beginPath()
      ctx.moveTo(op.points[0].x, op.points[0].y)
      for (let i = 1; i < op.points.length; i++) {
        ctx.lineTo(op.points[i].x, op.points[i].y)
      }
      ctx.stroke()
      break
    }
    case 'rectangle': {
      ctx.strokeStyle = op.color
      ctx.lineWidth = op.size
      ctx.globalCompositeOperation = 'source-over'
      ctx.strokeRect(op.origin.x, op.origin.y, op.width, op.height)
      break
    }
    case 'circle': {
      ctx.strokeStyle = op.color
      ctx.lineWidth = op.size
      ctx.globalCompositeOperation = 'source-over'
      ctx.beginPath()
      ctx.arc(op.center.x, op.center.y, op.radius, 0, Math.PI * 2)
      ctx.stroke()
      break
    }
    case 'line': {
      ctx.strokeStyle = op.color
      ctx.lineWidth = op.size
      ctx.globalCompositeOperation = 'source-over'
      ctx.beginPath()
      ctx.moveTo(op.start.x, op.start.y)
      ctx.lineTo(op.end.x, op.end.y)
      ctx.stroke()
      break
    }
    case 'eraser': {
      if (op.points.length < 2) return
      ctx.globalCompositeOperation = 'destination-out'
      ctx.lineWidth = op.size
      ctx.beginPath()
      ctx.moveTo(op.points[0].x, op.points[0].y)
      for (let i = 1; i < op.points.length; i++) {
        ctx.lineTo(op.points[i].x, op.points[i].y)
      }
      ctx.stroke()
      ctx.globalCompositeOperation = 'source-over'
      break
    }
  }
}

export const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer, width: number, height: number): void => {
  if (!layer.visible) return

  const offscreen = document.createElement('canvas')
  offscreen.width = width
  offscreen.height = height
  const offCtx = offscreen.getContext('2d')!

  for (const op of layer.ops) {
    renderOp(offCtx, op)
  }

  ctx.drawImage(offscreen, 0, 0)
}

export const renderAllLayers = (ctx: CanvasRenderingContext2D, state: CanvasState): void => {
  ctx.clearRect(0, 0, state.width, state.height)

  // White background
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, state.width, state.height)

  for (const layer of state.layers) {
    renderLayer(ctx, layer, state.width, state.height)
  }
}

export const renderLayerThumbnail = (layer: Layer, width: number, height: number, thumbWidth: number, thumbHeight: number): HTMLCanvasElement => {
  const thumb = document.createElement('canvas')
  thumb.width = thumbWidth
  thumb.height = thumbHeight
  const ctx = thumb.getContext('2d')!

  ctx.fillStyle = '#f0f0f0'
  ctx.fillRect(0, 0, thumbWidth, thumbHeight)

  ctx.scale(thumbWidth / width, thumbHeight / height)

  for (const op of layer.ops) {
    renderOp(ctx, op)
  }

  return thumb
}

export const canvasToBlob = (canvas: HTMLCanvasElement): Promise<Blob> =>
  new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) resolve(blob)
      else reject(new Error('Failed to create blob from canvas'))
    }, 'image/png')
  })

export const canvasToDataURL = (canvas: HTMLCanvasElement): string =>
  canvas.toDataURL('image/png')

import type { ToolKind, Point, DrawOp } from './types'

export type ActiveStroke = {
  tool: ToolKind
  color: string
  size: number
  points: Point[]
  startPoint: Point
}

export const beginStroke = (tool: ToolKind, point: Point, color: string, size: number): ActiveStroke => ({
  tool,
  color,
  size,
  points: [point],
  startPoint: point,
})

export const addPoint = (stroke: ActiveStroke, point: Point): ActiveStroke => ({
  ...stroke,
  points: [...stroke.points, point],
})

export const finalizeStroke = (stroke: ActiveStroke, endPoint: Point): DrawOp | null => {
  switch (stroke.tool) {
    case 'freehand': {
      if (stroke.points.length < 2) return null
      return {
        kind: 'freehand',
        points: stroke.points,
        color: stroke.color,
        size: stroke.size,
      }
    }
    case 'eraser': {
      if (stroke.points.length < 2) return null
      return {
        kind: 'eraser',
        points: stroke.points,
        size: stroke.size,
      }
    }
    case 'rectangle': {
      const width = endPoint.x - stroke.startPoint.x
      const height = endPoint.y - stroke.startPoint.y
      if (width === 0 && height === 0) return null
      return {
        kind: 'rectangle',
        origin: {
          x: Math.min(stroke.startPoint.x, endPoint.x),
          y: Math.min(stroke.startPoint.y, endPoint.y),
        },
        width: Math.abs(width),
        height: Math.abs(height),
        color: stroke.color,
        size: stroke.size,
      }
    }
    case 'circle': {
      const dx = endPoint.x - stroke.startPoint.x
      const dy = endPoint.y - stroke.startPoint.y
      const radius = Math.sqrt(dx * dx + dy * dy)
      if (radius === 0) return null
      return {
        kind: 'circle',
        center: stroke.startPoint,
        radius,
        color: stroke.color,
        size: stroke.size,
      }
    }
    case 'line': {
      if (stroke.startPoint.x === endPoint.x && stroke.startPoint.y === endPoint.y) return null
      return {
        kind: 'line',
        start: stroke.startPoint,
        end: endPoint,
        color: stroke.color,
        size: stroke.size,
      }
    }
  }
}

import type { SerializedState, CanvasState } from './types'

const STATE_PATH = 'data/state.json'

export const saveState = async (state: CanvasState): Promise<void> => {
  const serialized: SerializedState = {
    width: state.width,
    height: state.height,
    layers: state.layers,
    activeLayerIndex: state.activeLayerIndex,
  }
  await Bun.write(STATE_PATH, JSON.stringify(serialized, null, 2))
}

export const loadState = async (): Promise<SerializedState | null> => {
  const file = Bun.file(STATE_PATH)
  if (!(await file.exists())) return null

  const text = await file.text()
  return JSON.parse(text) as SerializedState
}

export const savePNG = async (dataUrl: string, path: string): Promise<void> => {
  const base64 = dataUrl.replace(/^data:image\/png;base64,/, '')
  const buffer = Buffer.from(base64, 'base64')
  await Bun.write(path, buffer)
}

export const loadPNG = async (path: string): Promise<Uint8Array | null> => {
  const file = Bun.file(path)
  if (!(await file.exists())) return null

  const arrayBuffer = await file.arrayBuffer()
  return new Uint8Array(arrayBuffer)
}

