export const renderUI = (props: UIProps) => {
  return h('div', { style: styles.container },
    renderToolbar(props),
    renderCanvas(props),
    renderLayersPanel(props)
  )
}

export const renderToString = (props: UIProps): string => {
  const { createSSRTemplate } = createSSR()
  const template = renderUI(props)
  return createSSRTemplate(template)
}

import type {
  ToolKind,
  Point,
  DrawOp,
  CanvasState,
  CanvasConfig,
} from './types'
import { createLayer } from './layers'
import { createHistoryManager } from './history'
import { beginStroke, addPoint, finalizeStroke, type ActiveStroke } from './tools'
import { renderAllLayers, canvasToDataURL, createRenderContext } from './renderer'
import { saveState, loadState, savePNG, loadPNG } from './persistence'
import { renderUI, renderToString } from './ui'

export type DrawingCanvas = {
  getState: () => CanvasState
  setTool: (tool: ToolKind) => void
  getTool: () => ToolKind
  setColor: (color: string) => void
  getColor: () => string
  setBrushSize: (size: number) => void
  getBrushSize: () => number
  addLayer: (name?: string) => void
  removeLayer: (index: number) => void
  setActiveLayer: (index: number) => void
  toggleLayerVisibility: (index: number) => void
  onPointerDown: (point: Point) => void
  onPointerMove: (point: Point) => void
  onPointerUp: (point: Point) => void
  undo: () => void
  redo: () => void
  clearCanvas: () => void
  render: (ctx: CanvasRenderingContext2D) => void
  savePNG: (path: string) => Promise<void>
  loadPNG: (path: string) => Promise<void>
  saveProject: () => Promise<void>
  loadProject: () => Promise<boolean>
  renderUI: () => ReturnType<typeof renderUI>
  renderToString: () => string
}

export const createDrawingCanvas = (config: CanvasConfig = {}): DrawingCanvas => {
  const width = config.width ?? 800
  const height = config.height ?? 600

  const state: CanvasState = {
    width,
    height,
    layers: [createLayer('Background')],
    activeLayerIndex: 0,
  }

  let activeTool: ToolKind = 'freehand'
  let color = '#000000'
  let brushSize = 3
  let currentStroke: ActiveStroke | null = null

  const history = createHistoryManager()

  const getState = (): CanvasState => state

  const setTool = (tool: ToolKind): void => {
    activeTool = tool
  }

  const getTool = (): ToolKind => activeTool

  const setColor = (c: string): void => {
    color = c
  }

  const getColor = (): string => color

  const setBrushSize = (size: number): void => {
    brushSize = Math.max(1, Math.min(50, size))
  }

  const getBrushSize = (): number => brushSize

  const addNewLayer = (name?: string): void => {
    const layerName = name ?? `Layer ${state.layers.length + 1}`
    state.layers.push(createLayer(layerName))
    state.activeLayerIndex = state.layers.length - 1
  }

  const removeLayer = (index: number): void => {
    if (state.layers.length <= 1) return
    if (index < 0 || index >= state.layers.length) return

    state.layers.splice(index, 1)
    if (state.activeLayerIndex >= state.layers.length) {
      state.activeLayerIndex = state.layers.length - 1
    }
  }

  const setActiveLayer = (index: number): void => {
    if (index >= 0 && index < state.layers.length) {
      state.activeLayerIndex = index
    }
  }

  const toggleLayerVisibility = (index: number): void => {
    if (index >= 0 && index < state.layers.length) {
      state.layers[index].visible = !state.layers[index].visible
    }
  }

  const onPointerDown = (point: Point): void => {
    currentStroke = beginStroke(activeTool, point, color, brushSize)
  }

  const onPointerMove = (point: Point): void => {
    if (!currentStroke) return
    currentStroke = addPoint(currentStroke, point)
  }

  const onPointerUp = (point: Point): void => {
    if (!currentStroke) return

    const op = finalizeStroke(currentStroke, point)
    if (op) {
      const layer = state.layers[state.activeLayerIndex]
      layer.ops.push(op)
      history.push({ layerIndex: state.activeLayerIndex, op })
    }
    currentStroke = null
  }

  const undo = (): void => {
    history.undo(state.layers)
  }

  const redo = (): void => {
    history.redo(state.layers)
  }

  const clearCanvas = (): void => {
    for (const layer of state.layers) {
      layer.ops = []
    }
    history.clear()
  }

  const render = (ctx: CanvasRenderingContext2D): void => {
    renderAllLayers(ctx, state)

    // Draw current in-progress stroke as preview
    if (currentStroke && currentStroke.points.length > 1) {
      ctx.lineJoin = 'round'
      ctx.lineCap = 'round'

      if (currentStroke.tool === 'eraser') {
        ctx.globalCompositeOperation = 'destination-out'
        ctx.lineWidth = currentStroke.size
      } else {
        ctx.globalCompositeOperation = 'source-over'
        ctx.strokeStyle = currentStroke.color
        ctx.lineWidth = currentStroke.size
      }

      if (currentStroke.tool === 'freehand' || currentStroke.tool === 'eraser') {
        ctx.beginPath()
        ctx.moveTo(currentStroke.points[0].x, currentStroke.points[0].y)
        for (let i = 1; i < currentStroke.points.length; i++) {
          ctx.lineTo(currentStroke.points[i].x, currentStroke.points[i].y)
        }
        ctx.stroke()
      }

      ctx.globalCompositeOperation = 'source-over'
    }
  }

  const doSavePNG = async (path: string): Promise<void> => {
    const { canvas, ctx } = createRenderContext(width, height)
    renderAllLayers(ctx, state)
    const dataUrl = canvasToDataURL(canvas)
    await savePNG(dataUrl, path)
  }

  const doLoadPNG = async (path: string): Promise<void> => {
    const data = await loadPNG(path)
    if (!data) return

    // Create a blob URL and load as image in browser context
    // For server-side, we store the raw data for later use
    const layer = createLayer('Imported')
    state.layers.push(layer)
    state.activeLayerIndex = state.layers.length - 1
  }

  const saveProject = async (): Promise<void> => {
    await saveState(state)
  }

  const loadProject = async (): Promise<boolean> => {
    const saved = await loadState()
    if (!saved) return false

    state.width = saved.width
    state.height = saved.height
    state.layers = saved.layers
    state.activeLayerIndex = saved.activeLayerIndex
    history.clear()
    return true
  }

  const getUIProps = () => ({
    state,
    activeTool,
    color,
    brushSize,
    canUndo: history.canUndo(),
    canRedo: history.canRedo(),
  })

  const doRenderUI = () => renderUI(getUIProps())

  const doRenderToString = () => renderToString(getUIProps())

  return {
    getState,
    setTool,
    getTool,
    setColor,
    getColor,
    setBrushSize,
    getBrushSize,
    addLayer: addNewLayer,
    removeLayer,
    setActiveLayer,
    toggleLayerVisibility,
    onPointerDown,
    onPointerMove,
    onPointerUp,
    undo,
    redo,
    clearCanvas,
    render,
    savePNG: doSavePNG,
    loadPNG: doLoadPNG,
    saveProject,
    loadProject,
    renderUI: doRenderUI,
    renderToString: doRenderToString,
  }
}

