import type { CanvasState, Layer } from './types'

export type Snapshot = {
  layers: Layer[]
  activeLayerId: string
}

const takeSnapshot = (state: CanvasState): Snapshot => ({
  layers: state.layers.map((l) => ({
    ...l,
    actions: [...l.actions],
  })),
  activeLayerId: state.activeLayerId,
})

const applySnapshot = (state: CanvasState, snapshot: Snapshot): CanvasState => ({
  ...state,
  layers: snapshot.layers.map((l) => ({
    ...l,
    actions: [...l.actions],
  })),
  activeLayerId: snapshot.activeLayerId,
})

export type HistoryManager = {
  push: (state: CanvasState) => void
  undo: (current: CanvasState) => CanvasState | null
  redo: (current: CanvasState) => CanvasState | null
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
}

export const createHistoryManager = (maxSize = 50): HistoryManager => {
  const undoStack: Snapshot[] = []
  const redoStack: Snapshot[] = []

  return {
    push: (state) => {
      undoStack.push(takeSnapshot(state))
      if (undoStack.length > maxSize) {
        undoStack.shift()
      }
      redoStack.length = 0
    },

    undo: (current) => {
      const snapshot = undoStack.pop()
      if (!snapshot) return null
      redoStack.push(takeSnapshot(current))
      return applySnapshot(current, snapshot)
    },

    redo: (current) => {
      const snapshot = redoStack.pop()
      if (!snapshot) return null
      undoStack.push(takeSnapshot(current))
      return applySnapshot(current, snapshot)
    },

    canUndo: () => undoStack.length > 0,
    canRedo: () => redoStack.length > 0,

    clear: () => {
      undoStack.length = 0
      redoStack.length = 0
    },
  }
}

import type { Layer, CanvasState } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter += 1
  return {
    id: `layer-${layerCounter}-${Date.now()}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    opacity: 1,
    actions: [],
  }
}

export const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name)
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const filtered = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId =
    state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId
  return { ...state, layers: filtered, activeLayerId }
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
})

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

export const moveLayer = (
  state: CanvasState,
  layerId: string,
  direction: 'up' | 'down',
): CanvasState => {
  const idx = state.layers.findIndex((l) => l.id === layerId)
  if (idx === -1) return state
  const newIdx = direction === 'up' ? idx + 1 : idx - 1
  if (newIdx < 0 || newIdx >= state.layers.length) return state
  const layers = [...state.layers]
  const [moved] = layers.splice(idx, 1)
  layers.splice(newIdx, 0, moved)
  return { ...state, layers }
}

export const setLayerOpacity = (
  state: CanvasState,
  layerId: string,
  opacity: number,
): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, opacity: Math.max(0, Math.min(1, opacity)) } : l,
  ),
})

export const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId)

export const clearLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, actions: [] } : l)),
})

export const clearAllLayers = (state: CanvasState): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => ({ ...l, actions: [] })),
})

import type { CanvasState, DrawAction, Point, StrokeRecord, ShapeRecord, ToolKind } from './types'
import { getActiveLayer } from './layers'

export type DrawingSession = {
  tool: ToolKind
  color: string
  size: number
  points: Point[]
  startPoint: Point
}

export const startDrawing = (
  tool: ToolKind,
  color: string,
  size: number,
  point: Point,
): DrawingSession => ({
  tool,
  color,
  size,
  points: [point],
  startPoint: point,
})

export const addPoint = (session: DrawingSession, point: Point): DrawingSession => ({
  ...session,
  points: [...session.points, point],
})

export const finishDrawing = (session: DrawingSession, endPoint: Point): DrawAction => {
  if (session.tool === 'rectangle' || session.tool === 'circle' || session.tool === 'line') {
    return {
      tool: session.tool,
      color: session.color,
      size: session.size,
      start: session.startPoint,
      end: endPoint,
    } as ShapeRecord
  }
  return {
    tool: session.tool,
    color: session.color,
    size: session.size,
    points: [...session.points, endPoint],
  } as StrokeRecord
}

export const commitAction = (state: CanvasState, action: DrawAction): CanvasState => {
  const activeLayer = getActiveLayer(state)
  if (!activeLayer) return state
  return {
    ...state,
    layers: state.layers.map((l) =>
      l.id === activeLayer.id ? { ...l, actions: [...l.actions, action] } : l,
    ),
  }
}

export const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  if ('points' in action) {
    const stroke = action as StrokeRecord
    ctx.strokeStyle = stroke.tool === 'eraser' ? '#ffffff' : stroke.color
    ctx.lineWidth = stroke.size
    ctx.globalCompositeOperation = stroke.tool === 'eraser' ? 'destination-out' : 'source-over'

    if (stroke.points.length < 2) {
      ctx.beginPath()
      ctx.arc(stroke.points[0].x, stroke.points[0].y, stroke.size / 2, 0, Math.PI * 2)
      ctx.fillStyle = stroke.tool === 'eraser' ? '#ffffff' : stroke.color
      ctx.fill()
      return
    }

    ctx.beginPath()
    ctx.moveTo(stroke.points[0].x, stroke.points[0].y)
    for (let i = 1; i < stroke.points.length; i++) {
      const prev = stroke.points[i - 1]
      const curr = stroke.points[i]
      const midX = (prev.x + curr.x) / 2
      const midY = (prev.y + curr.y) / 2
      ctx.quadraticCurveTo(prev.x, prev.y, midX, midY)
    }
    const last = stroke.points[stroke.points.length - 1]
    ctx.lineTo(last.x, last.y)
    ctx.stroke()
    ctx.globalCompositeOperation = 'source-over'
  } else {
    const shape = action as ShapeRecord
    ctx.strokeStyle = shape.color
    ctx.lineWidth = shape.size
    ctx.globalCompositeOperation = 'source-over'

    if (shape.tool === 'rectangle') {
      const x = Math.min(shape.start.x, shape.end.x)
      const y = Math.min(shape.start.y, shape.end.y)
      const w = Math.abs(shape.end.x - shape.start.x)
      const h = Math.abs(shape.end.y - shape.start.y)
      if (shape.fill) {
        ctx.fillStyle = shape.fill
        ctx.fillRect(x, y, w, h)
      }
      ctx.strokeRect(x, y, w, h)
    } else if (shape.tool === 'circle') {
      const cx = (shape.start.x + shape.end.x) / 2
      const cy = (shape.start.y + shape.end.y) / 2
      const rx = Math.abs(shape.end.x - shape.start.x) / 2
      const ry = Math.abs(shape.end.y - shape.start.y) / 2
      ctx.beginPath()
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      if (shape.fill) {
        ctx.fillStyle = shape.fill
        ctx.fill()
      }
      ctx.stroke()
    } else if (shape.tool === 'line') {
      ctx.beginPath()
      ctx.moveTo(shape.start.x, shape.start.y)
      ctx.lineTo(shape.end.x, shape.end.y)
      ctx.stroke()
    }
  }
}

export const renderLayer = (
  ctx: CanvasRenderingContext2D,
  actions: DrawAction[],
  opacity: number,
): void => {
  ctx.save()
  ctx.globalAlpha = opacity
  for (const action of actions) {
    renderAction(ctx, action)
  }
  ctx.restore()
}

export const renderAllLayers = (
  ctx: CanvasRenderingContext2D,
  state: CanvasState,
): void => {
  ctx.clearRect(0, 0, state.width, state.height)
  ctx.fillStyle = state.backgroundColor
  ctx.fillRect(0, 0, state.width, state.height)

  for (const layer of state.layers) {
    if (!layer.visible) continue
    renderLayer(ctx, layer.actions, layer.opacity)
  }
}

export const renderPreview = (
  ctx: CanvasRenderingContext2D,
  session: DrawingSession,
  currentPoint: Point,
): void => {
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  if (session.tool === 'rectangle') {
    ctx.strokeStyle = session.color
    ctx.lineWidth = session.size
    const x = Math.min(session.startPoint.x, currentPoint.x)
    const y = Math.min(session.startPoint.y, currentPoint.y)
    const w = Math.abs(currentPoint.x - session.startPoint.x)
    const h = Math.abs(currentPoint.y - session.startPoint.y)
    ctx.strokeRect(x, y, w, h)
  } else if (session.tool === 'circle') {
    ctx.strokeStyle = session.color
    ctx.lineWidth = session.size
    const cx = (session.startPoint.x + currentPoint.x) / 2
    const cy = (session.startPoint.y + currentPoint.y) / 2
    const rx = Math.abs(currentPoint.x - session.startPoint.x) / 2
    const ry = Math.abs(currentPoint.y - session.startPoint.y) / 2
    ctx.beginPath()
    ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
    ctx.stroke()
  } else if (session.tool === 'line') {
    ctx.strokeStyle = session.color
    ctx.lineWidth = session.size
    ctx.beginPath()
    ctx.moveTo(session.startPoint.x, session.startPoint.y)
    ctx.lineTo(currentPoint.x, currentPoint.y)
    ctx.stroke()
  }
}

import type { CanvasState, SavedDrawing, DrawingMetadata } from './types'

const DATA_PATH = './data/drawings.json'

const loadDrawings = async (): Promise<SavedDrawing[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as SavedDrawing[]
}

const saveDrawings = async (drawings: SavedDrawing[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(drawings, null, 2))
}

export const listDrawings = async (): Promise<DrawingMetadata[]> => {
  const drawings = await loadDrawings()
  return drawings.map((d) => d.metadata)
}

export const saveDrawing = async (
  state: CanvasState,
  name: string,
  existingId?: string,
): Promise<SavedDrawing> => {
  const drawings = await loadDrawings()
  const now = new Date().toISOString()
  const id = existingId ?? `drawing-${Date.now()}`

  const metadata: DrawingMetadata = {
    id,
    name,
    createdAt: existingId
      ? (drawings.find((d) => d.metadata.id === existingId)?.metadata.createdAt ?? now)
      : now,
    updatedAt: now,
    width: state.width,
    height: state.height,
    layerCount: state.layers.length,
  }

  const saved: SavedDrawing = { metadata, state }
  const idx = drawings.findIndex((d) => d.metadata.id === id)
  if (idx >= 0) {
    drawings[idx] = saved
  } else {
    drawings.push(saved)
  }

  await saveDrawings(drawings)
  return saved
}

export const loadDrawing = async (id: string): Promise<SavedDrawing | null> => {
  const drawings = await loadDrawings()
  return drawings.find((d) => d.metadata.id === id) ?? null
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const drawings = await loadDrawings()
  const filtered = drawings.filter((d) => d.metadata.id !== id)
  if (filtered.length === drawings.length) return false
  await saveDrawings(filtered)
  return true
}

export const exportCanvasToPng = (canvas: HTMLCanvasElement): string =>
  canvas.toDataURL('image/png')

export const downloadPng = (canvas: HTMLCanvasElement, filename = 'drawing.png'): void => {
  const dataUrl = exportCanvasToPng(canvas)
  const link = document.createElement('a')
  link.download = filename
  link.href = dataUrl
  link.click()
}

export const loadImageToCanvas = (
  ctx: CanvasRenderingContext2D,
  src: string,
): Promise<void> =>
  new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      ctx.drawImage(img, 0, 0)
      resolve()
    }
    img.onerror = reject
    img.src = src
  })

