        renderCanvas(state.width, state.height),
      ),
      renderLayersPanel(state),
    ),
  )

export { styles }

import type { CanvasState, ToolState, ToolKind, Point } from './types'
import { createLayer, addLayer, removeLayer, toggleLayerVisibility, setActiveLayer, moveLayer, clearLayer, clearAllLayers } from './layers'
import { createHistoryManager } from './history'
import { startDrawing, addPoint, finishDrawing, commitAction, renderAllLayers, renderPreview, type DrawingSession } from './canvas-engine'
import { saveDrawing, loadDrawing, listDrawings, downloadPng, loadImageToCanvas } from './storage'
import { renderApp } from './render'
import { createSSR } from 'plaited'

const DEFAULT_WIDTH = 800
const DEFAULT_HEIGHT = 600

const createInitialState = (): CanvasState => {
  const layer = createLayer('Background')
  return {
    width: DEFAULT_WIDTH,
    height: DEFAULT_HEIGHT,
    layers: [layer],
    activeLayerId: layer.id,
    backgroundColor: '#ffffff',
  }
}

const createInitialToolState = (): ToolState => ({
  activeTool: 'brush',
  color: '#000000',
  fillColor: '#transparent',
  brushSize: 4,
  showFill: false,
})

export type DrawingCanvasApp = {
  getState: () => CanvasState
  getToolState: () => ToolState
  setTool: (tool: ToolKind) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  undo: () => void
  redo: () => void
  clearActiveLayer: () => void
  clearAll: () => void
  addLayer: (name?: string) => void
  removeActiveLayer: () => void
  toggleLayerVisibility: (layerId: string) => void
  setActiveLayer: (layerId: string) => void
  moveLayerUp: () => void
  moveLayerDown: () => void
  onPointerDown: (point: Point) => void
  onPointerMove: (point: Point) => void
  onPointerUp: (point: Point) => void
  save: (name: string) => Promise<void>
  load: (id: string) => Promise<void>
  list: () => Promise<ReturnType<typeof listDrawings>>
  exportPng: () => void
  importPng: (src: string) => Promise<void>
  render: () => void
  mount: (container: HTMLElement) => void
  toSSR: () => string
}

export const createDrawingCanvas = (): DrawingCanvasApp => {
  let state = createInitialState()
  let toolState = createInitialToolState()
  const history = createHistoryManager()
  let activeSession: DrawingSession | null = null
  let mainCanvas: HTMLCanvasElement | null = null
  let previewCanvas: HTMLCanvasElement | null = null
  let container: HTMLElement | null = null

  const getCtx = (canvas: HTMLCanvasElement | null) =>
    canvas?.getContext('2d') ?? null

  const redraw = () => {
    const ctx = getCtx(mainCanvas)
    if (!ctx) return
    renderAllLayers(ctx, state)
  }

  const clearPreview = () => {
    const ctx = getCtx(previewCanvas)
    if (!ctx || !previewCanvas) return
    ctx.clearRect(0, 0, previewCanvas.width, previewCanvas.height)
  }

  const updateThumbnails = () => {
    if (!container) return
    for (const layer of state.layers) {
      const thumb = container.querySelector(`[p-target="thumb-${layer.id}"]`) as HTMLCanvasElement | null
      if (!thumb) continue
      const tctx = thumb.getContext('2d')
      if (!tctx) continue
      tctx.clearRect(0, 0, 36, 36)
      tctx.fillStyle = '#ffffff'
      tctx.fillRect(0, 0, 36, 36)
      const scaleX = 36 / state.width
      const scaleY = 36 / state.height
      tctx.save()
      tctx.scale(scaleX, scaleY)
      tctx.globalAlpha = layer.opacity
      for (const action of layer.actions) {
        const { renderAction } = require('./canvas-engine')
        renderAction(tctx, action)
      }
      tctx.restore()
    }
  }

  const renderUI = () => {
    if (!container) return
    const vdom = renderApp(state, toolState, history.canUndo(), history.canRedo())
    container.innerHTML = ''
    const ssr = createSSR()
    const html = ssr(vdom)
    container.innerHTML = html
    mainCanvas = container.querySelector('[p-target="main-canvas"]') as HTMLCanvasElement
    previewCanvas = container.querySelector('[p-target="preview-canvas"]') as HTMLCanvasElement
    bindCanvasEvents()
    redraw()
    updateThumbnails()
  }

  const bindCanvasEvents = () => {
    if (!previewCanvas) return
    const getPoint = (e: PointerEvent): Point => {
      const rect = previewCanvas!.getBoundingClientRect()
      return { x: e.clientX - rect.left, y: e.clientY - rect.top }
    }

    const interactiveCanvas = previewCanvas
    interactiveCanvas.style.pointerEvents = 'auto'

    interactiveCanvas.onpointerdown = (e) => {
      interactiveCanvas.setPointerCapture(e.pointerId)
      app.onPointerDown(getPoint(e))
    }
    interactiveCanvas.onpointermove = (e) => {
      if (activeSession) app.onPointerMove(getPoint(e))
    }
    interactiveCanvas.onpointerup = (e) => {
      app.onPointerUp(getPoint(e))
    }

    bindToolbarEvents()
  }

  const bindToolbarEvents = () => {
    if (!container) return

    container.querySelectorAll('[p-trigger]').forEach((el) => {
      const trigger = el.getAttribute('p-trigger') ?? ''

      if (trigger.startsWith('tool-select:')) {
        const tool = trigger.split(':')[1] as ToolKind
        ;(el as HTMLElement).onclick = () => app.setTool(tool)
      } else if (trigger === 'color-change') {
        ;(el as HTMLInputElement).oninput = (e) =>
          app.setColor((e.target as HTMLInputElement).value)
      } else if (trigger === 'size-change') {
        ;(el as HTMLInputElement).oninput = (e) =>
          app.setBrushSize(Number((e.target as HTMLInputElement).value))
      } else if (trigger === 'undo') {
        ;(el as HTMLElement).onclick = () => app.undo()
      } else if (trigger === 'redo') {
        ;(el as HTMLElement).onclick = () => app.redo()
      } else if (trigger === 'clear-layer') {
        ;(el as HTMLElement).onclick = () => app.clearActiveLayer()
      } else if (trigger === 'clear-all') {
        ;(el as HTMLElement).onclick = () => app.clearAll()
      } else if (trigger === 'save-png') {
        ;(el as HTMLElement).onclick = () => app.exportPng()
      } else if (trigger === 'load-png') {
        ;(el as HTMLElement).onclick = () => {
          const input = document.createElement('input')
          input.type = 'file'
          input.accept = 'image/png'
          input.onchange = () => {
            const file = input.files?.[0]
            if (!file) return
            const reader = new FileReader()
            reader.onload = () => app.importPng(reader.result as string)
            reader.readAsDataURL(file)
          }
          input.click()
        }
      } else if (trigger === 'save-drawing') {
        ;(el as HTMLElement).onclick = () => {
          const name = prompt('Drawing name:') ?? 'Untitled'
          app.save(name)
        }
      } else if (trigger === 'layer-add') {
        ;(el as HTMLElement).onclick = () => app.addLayer()
      } else if (trigger === 'layer-remove') {
        ;(el as HTMLElement).onclick = () => app.removeActiveLayer()
      } else if (trigger === 'layer-up') {
        ;(el as HTMLElement).onclick = () => app.moveLayerUp()
      } else if (trigger === 'layer-down') {
        ;(el as HTMLElement).onclick = () => app.moveLayerDown()
      } else if (trigger.startsWith('layer-select:')) {
        const id = trigger.split(':')[1]
        ;(el as HTMLElement).onclick = () => app.setActiveLayer(id)
      } else if (trigger.startsWith('layer-toggle:')) {
        const id = trigger.split(':')[1]
        ;(el as HTMLElement).onclick = (e) => {
          e.stopPropagation()
          app.toggleLayerVisibility(id)
        }
      }
    })
  }

  const app: DrawingCanvasApp = {
    getState: () => state,
    getToolState: () => toolState,

    setTool: (tool) => {
      toolState = { ...toolState, activeTool: tool }
      renderUI()
    },

    setColor: (color) => {
      toolState = { ...toolState, color }
    },

    setBrushSize: (size) => {
      toolState = { ...toolState, brushSize: size }
    },

    undo: () => {
      const prev = history.undo(state)
      if (prev) {
        state = prev
        renderUI()
      }
    },

    redo: () => {
      const next = history.redo(state)
      if (next) {
        state = next
        renderUI()
      }
    },

    clearActiveLayer: () => {
      history.push(state)
      state = clearLayer(state, state.activeLayerId)
      renderUI()
    },

    clearAll: () => {
      history.push(state)
      state = clearAllLayers(state)
      renderUI()
    },

    addLayer: (name) => {
      history.push(state)
      state = addLayer(state, name)
      renderUI()
    },

    removeActiveLayer: () => {
      if (state.layers.length <= 1) return
      history.push(state)
      state = removeLayer(state, state.activeLayerId)
      renderUI()
    },

    toggleLayerVisibility: (layerId) => {
      state = toggleLayerVisibility(state, layerId)
      renderUI()
    },

    setActiveLayer: (layerId) => {
      state = setActiveLayer(state, layerId)
      renderUI()
    },

    moveLayerUp: () => {
      history.push(state)
      state = moveLayer(state, state.activeLayerId, 'up')
      renderUI()
    },

    moveLayerDown: () => {
      history.push(state)
      state = moveLayer(state, state.activeLayerId, 'down')
      renderUI()
    },

    onPointerDown: (point) => {
      history.push(state)
      const color = toolState.activeTool === 'eraser' ? '#ffffff' : toolState.color
      activeSession = startDrawing(toolState.activeTool, color, toolState.brushSize, point)
    },

    onPointerMove: (point) => {
      if (!activeSession) return

      if (activeSession.tool === 'brush' || activeSession.tool === 'eraser') {
        activeSession = addPoint(activeSession, point)
        const action = finishDrawing(activeSession, point)
        const ctx = getCtx(mainCanvas)
        if (ctx) {
          renderAllLayers(ctx, state)
          const { renderAction } = require('./canvas-engine')
          renderAction(ctx, action)
        }
      } else {
        redraw()
        const ctx = getCtx(previewCanvas)
        if (ctx && previewCanvas) {
          ctx.clearRect(0, 0, previewCanvas.width, previewCanvas.height)
          renderPreview(ctx, activeSession, point)
        }
      }
    },

    onPointerUp: (point) => {
      if (!activeSession) return
      const action = finishDrawing(activeSession, point)
      state = commitAction(state, action)
      activeSession = null
      clearPreview()
      redraw()
      updateThumbnails()
    },

    save: async (name) => {
      await saveDrawing(state, name)
    },

    load: async (id) => {
      const drawing = await loadDrawing(id)
      if (drawing) {
        state = drawing.state
        history.clear()
        renderUI()
      }
    },

    list: () => listDrawings(),

    exportPng: () => {
      if (mainCanvas) downloadPng(mainCanvas)
    },

    importPng: async (src) => {
      history.push(state)
      const ctx = getCtx(mainCanvas)
      if (ctx) {
        await loadImageToCanvas(ctx, src)
      }
    },

    render: () => renderUI(),

    mount: (el) => {
      container = el
      document.addEventListener('keydown', (e) => {
        if (e.ctrlKey || e.metaKey) {
          if (e.key === 'z' && !e.shiftKey) {
            e.preventDefault()
            app.undo()
          } else if ((e.key === 'z' && e.shiftKey) || e.key === 'y') {
            e.preventDefault()
            app.redo()
          }
        }
      })
      renderUI()
    },

    toSSR: () => {
      const ssr = createSSR()
      const vdom = renderApp(state, toolState, history.canUndo(), history.canRedo())
      return ssr(vdom)
    },
  }

  return app
}

export { createInitialState, createInitialToolState }
export type { CanvasState, ToolState, ToolKind, Point } from './types'
export { createHistoryManager } from './history'
export { renderApp } from './render'
